class MLP(nn.Module):
    """MLP with squared LeakyReLU activation."""
    def __init__(self, dim, mult=4):
        super().__init__()
        self.fc = CastedLinear(dim, mult * dim)
        self.proj = CastedLinear(mult * dim, dim)

    def forward(self, x):
        return self.proj(F.leaky_relu(self.fc(x), negative_slope=0.5).square())


